import requests
import time

def test_patient_sso_login_rate_limit_boundary():
    patient_id = '<fixture>test_patient_id</fixture>'
    bad_assertion = 'invalid.assertion'
    headers = {'Authorization': f'Bearer {bad_assertion}'}

    <helper_fn>reset_rate_limit_for_patient(patient_id)</helper_fn>
    <helper_fn>set_rate_limit_counter(patient_id, 4)</helper_fn>

    for i in range(2):
        response = requests.post(
            'http://localhost:8080/portal/login',
            headers=headers,
            timeout=5
        )
        if i < 1:
            assert response.status_code == 401, f"Attempt {i+1}: Expected 401"
        else:
            assert response.status_code == 429, f"Attempt {i+1}: Expected 429, got {response.status_code}"
            assert 'Retry-After' in response.headers, "Missing Retry-After header"
            assert 'error' in response.json(), "Missing error in 429 response"
